function debounce(fn, ms) {
    let t;
    return (...a) => {
        clearTimeout(t);
        t = setTimeout(() => fn(...a), ms);
    };
}

function throttle(fn, ms) {
    let last = 0;
    return (...a) => {
        const n = Date.now();
        if (n - last >= ms) {
            last = n;
            fn(...a);
        }
    };
}

